    lkp_LKPTRANS.LKP_EFFCT_END_DT,
    lkp_LKPTRANS.LKP_ACTIVE_FLAG,
    lkp_LKPTRANS.LKP_BDY_PRT_KEY,
    lkp_LKPTRANS.LKP_BDY_PRT_ID,
    lkp_LKPTRANS.LKP_CREATED_DT,
    lkp_LKPTRANS.LKP_MODIFIED_DT,
    lkp_LKPTRANS.LKP_RECORD_NM,
    lkp_LKPTRANS.LKP_RECORD_NB,
    lkp_LKPTRANS.LKP_BDY_PRT_NM,
    lkp_LKPTRANS.LKP_INJ_NTR_TX,
    SQ_ODS_SHMS_INCDNT_BDY_PRT.BDY_PRT_ID as SRC_BDY_PRT_ID,
    lkp_LKPTRANS.LKP_INJRY_ILLNSS_ID,
    lkp_LKPTRANS.LKP_HIGH_ENRGY_HZRD_TX,
    lkp_LKPTRANS.LKP_INJRY_SUSTAIN_1_TX,
    lkp_LKPTRANS.LKP_INJRY_SUSTAIN_2_TX,
    lkp_LKPTRANS.LKP_BDY_PRT_GRP_TX,
    SQ_ODS_SHMS_INCDNT_BDY_PRT.INJRY_ILLNSS_ID as SRC_INJRY_ILLNSS_ID,
   MD5(COALESCE(CAST(IFF((CREATED_DT IS NULL), '', TO_VARCHAR(CREATED_DT, 'MMDDYYYY')) AS VARCHAR), '')
     || COALESCE(CAST(IFF((MODIFIED_DT IS NULL), '', TO_VARCHAR(MODIFIED_DT, 'MMDDYYYY')) AS VARCHAR), '') 
     || COALESCE(CAST(IFF((RECORD_NM IS NULL), '', RECORD_NM) AS VARCHAR), '') 
     || COALESCE(CAST(IFF((RECORD_NB IS NULL),'0', RECORD_NB) AS VARCHAR), '') 
     || COALESCE(CAST(IFF((BDY_PRT_NM IS NULL), '', BDY_PRT_NM) AS VARCHAR), '') 
     || COALESCE(CAST(IFF((INJ_NTR_TX IS NULL), '', INJ_NTR_TX) AS VARCHAR), '')
     || COALESCE(CAST(IFF((HIGH_ENRGY_HZRD_TX IS NULL), '', HIGH_ENRGY_HZRD_TX) AS VARCHAR), '') 
     || COALESCE(CAST(IFF((INJRY_SUSTAIN_1_TX IS NULL), '', INJRY_SUSTAIN_1_TX) AS VARCHAR), '')
     || COALESCE(CAST(IFF((INJRY_SUSTAIN_2_TX IS NULL), '', INJRY_SUSTAIN_2_TX) AS VARCHAR), '') 
     || COALESCE(CAST(IFF((BDY_PRT_GRP_TX IS NULL), '', BDY_PRT_GRP_TX) AS VARCHAR), '')
    ) AS SRC_CHECKSUM,
    MD5(COALESCE(CAST(IFF((LKP_CREATED_DT IS NULL), '', TO_VARCHAR(LKP_CREATED_DT, 'MMDDYYYY')) AS VARCHAR), '')
     || COALESCE(CAST(IFF((LKP_MODIFIED_DT IS NULL), '', TO_VARCHAR(LKP_MODIFIED_DT, 'MMDDYYYY')) AS VARCHAR), '')
     || COALESCE(CAST(IFF((LKP_RECORD_NM IS NULL), '', LKP_RECORD_NM) AS VARCHAR), '') 
     || COALESCE(CAST(IFF((LKP_RECORD_NB IS NULL),'0', LKP_RECORD_NB) AS VARCHAR), '') 
     || COALESCE(CAST(IFF((LKP_BDY_PRT_NM IS NULL), '', LKP_BDY_PRT_NM) AS VARCHAR), '')
     || COALESCE(CAST(IFF((LKP_INJ_NTR_TX IS NULL), '', LKP_INJ_NTR_TX) AS VARCHAR), '') 
     || COALESCE(CAST(IFF((LKP_HIGH_ENRGY_HZRD_TX IS NULL), '', LKP_HIGH_ENRGY_HZRD_TX) AS VARCHAR), '') 
     || COALESCE(CAST(IFF((LKP_INJRY_SUSTAIN_1_TX IS NULL), '', LKP_INJRY_SUSTAIN_1_TX) AS VARCHAR), '') 
     || COALESCE(CAST(IFF((LKP_INJRY_SUSTAIN_2_TX IS NULL), '', LKP_INJRY_SUSTAIN_2_TX) AS VARCHAR), '') 
     || COALESCE(CAST(IFF((LKP_BDY_PRT_GRP_TX IS NULL), '', LKP_BDY_PRT_GRP_TX) AS VARCHAR), '')
    ) AS LKP_CHECKSUM,
    CURRENT_TIMESTAMP() AS O_EFFCT_SRT_DT,
    TRY_TO_DATE('12-31-9999', 'MM-DD-YYYY') AS O_EFFCT_END_DT,
    'Y' AS O_ACTIVE_FLAG,
    'SHMSUSER' AS EDW_LAST_UPDT_USERID1,
    CURRENT_TIMESTAMP() AS EDW_LAST_UPDT_TS1
  FROM SQ_ODS_SHMS_INCDNT_BDY_PRT
  LEFT JOIN (SELECT DIM.BDY_PRT_KEY as LKP_BDY_PRT_KEY, DIM.BDY_PRT_ID as LKP_BDY_PRT_ID, DIM.INJRY_ILLNSS_ID AS LKP_INJRY_ILLNSS_ID, DIM.CREATED_DT as LKP_CREATED_DT, DIM.MODIFIED_DT as LKP_MODIFIED_DT, DIM.RECORD_NM as LKP_RECORD_NM, DIM.RECORD_NB as LKP_RECORD_NB, DIM.BDY_PRT_NM as LKP_BDY_PRT_NM, DIM.INJ_NTR_TX as LKP_INJ_NTR_TX, DIM.EFFCT_STRT_DT as LKP_EFFCT_STRT_DT, DIM.EFFCT_END_DT as LKP_EFFCT_END_DT, DIM.ACTIVE_FLAG as LKP_ACTIVE_FLAG, DIM.HIGH_ENRGY_HZRD_TX AS LKP_HIGH_ENRGY_HZRD_TX, DIM.INJRY_SUSTAIN_1_TX AS LKP_INJRY_SUSTAIN_1_TX, DIM.INJRY_SUSTAIN_2_TX AS LKP_INJRY_SUSTAIN_2_TX, DIM.BDY_PRT_GRP_TX AS LKP_BDY_PRT_GRP_TX FROM CRPDB01_DEV_SANDBOX.SHMSADM.SHEMS_BDY_PRT_DIM DIM WHERE ACTIVE_FLAG='Y') lkp_LKPTRANS
    ON lkp_LKPTRANS.LKP_BDY_PRT_ID = SQ_ODS_SHMS_INCDNT_BDY_PRT.BDY_PRT_ID AND lkp_LKPTRANS.LKP_INJRY_ILLNSS_ID = SQ_ODS_SHMS_INCDNT_BDY_PRT.INJRY_ILLNSS_ID
),
 
EXPTRANS AS (
  SELECT
    EXPTRANS_step1.*,
    IFF((CAST(LKP_BDY_PRT_ID AS VARCHAR) ||  CAST(LKP_INJRY_ILLNSS_ID AS VARCHAR) IS NULL), 'I', IFF(NOT ((COALESCE(CAST(LKP_BDY_PRT_ID AS VARCHAR), '') || COALESCE(CAST(LKP_INJRY_ILLNSS_ID AS VARCHAR), '') IS NULL)) AND SRC_CHECKSUM <> LKP_CHECKSUM, 'U', NULL)) AS FLAG
  FROM EXPTRANS_step1
),
 
RTRTRANS_INSERT_ONLY AS (
  SELECT
    EXPTRANS.BDY_PRT_ID,
    EXPTRANS.INJRY_ILLNSS_ID,
    EXPTRANS.CREATED_DT,
    EXPTRANS.MODIFIED_DT,
    EXPTRANS.RECORD_NM,
    EXPTRANS.RECORD_NB,
    EXPTRANS.BDY_PRT_NM,
    EXPTRANS.INJ_NTR_TX,
    EXPTRANS.HIGH_ENRGY_HZRD_TX,
    EXPTRANS.INJRY_SUSTAIN_1_TX,
    EXPTRANS.INJRY_SUSTAIN_2_TX,
    EXPTRANS.BDY_PRT_GRP_TX,
    EXPTRANS.SRC_CHECKSUM,
    EXPTRANS.LKP_CHECKSUM,
    EXPTRANS.FLAG,
    EXPTRANS.O_EFFCT_SRT_DT,
    EXPTRANS.O_EFFCT_END_DT,
    EXPTRANS.O_ACTIVE_FLAG,
    EXPTRANS.EDW_LAST_UPDT_USERID1,
    EXPTRANS.EDW_LAST_UPDT_TS1
  FROM EXPTRANS
  WHERE FLAG = 'I'
)

,

RTRTRANS_INSERT_UPDATE AS (
  SELECT
    EXPTRANS.BDY_PRT_ID,
    EXPTRANS.INJRY_ILLNSS_ID,
    EXPTRANS.CREATED_DT,
    EXPTRANS.MODIFIED_DT,
    EXPTRANS.RECORD_NM,
    EXPTRANS.RECORD_NB,
    EXPTRANS.BDY_PRT_NM,
    EXPTRANS.INJ_NTR_TX,
    EXPTRANS.HIGH_ENRGY_HZRD_TX,
    EXPTRANS.INJRY_SUSTAIN_1_TX,
    EXPTRANS.INJRY_SUSTAIN_2_TX,
    EXPTRANS.BDY_PRT_GRP_TX,
    EXPTRANS.SRC_CHECKSUM,
    EXPTRANS.LKP_CHECKSUM,
    EXPTRANS.FLAG,
    EXPTRANS.O_EFFCT_SRT_DT,
    EXPTRANS.O_EFFCT_END_DT,
    EXPTRANS.O_ACTIVE_FLAG,
    EXPTRANS.EDW_LAST_UPDT_USERID1,
    EXPTRANS.EDW_LAST_UPDT_TS1,EXPTRANS.LKP_BDY_PRT_KEY
  FROM EXPTRANS
  WHERE FLAG = 'U'
)  ,
EXPTRANS1 AS (
  SELECT
    RTRTRANS_INSERT_UPDATE.*
  FROM RTRTRANS_INSERT_UPDATE
) ,

UPDTRANS2 AS (
  SELECT
    RTRTRANS_INSERT_ONLY.BDY_PRT_ID,
    RTRTRANS_INSERT_ONLY.INJRY_ILLNSS_ID,
    RTRTRANS_INSERT_ONLY.CREATED_DT,
    RTRTRANS_INSERT_ONLY.MODIFIED_DT,
    RTRTRANS_INSERT_ONLY.RECORD_NM,
    RTRTRANS_INSERT_ONLY.RECORD_NB,
    RTRTRANS_INSERT_ONLY.BDY_PRT_NM,
    RTRTRANS_INSERT_ONLY.INJ_NTR_TX,
    RTRTRANS_INSERT_ONLY.HIGH_ENRGY_HZRD_TX,
    RTRTRANS_INSERT_ONLY.INJRY_SUSTAIN_1_TX,
    RTRTRANS_INSERT_ONLY.INJRY_SUSTAIN_2_TX,
    RTRTRANS_INSERT_ONLY.BDY_PRT_GRP_TX,
    RTRTRANS_INSERT_ONLY.SRC_CHECKSUM,
    RTRTRANS_INSERT_ONLY.LKP_CHECKSUM,
    RTRTRANS_INSERT_ONLY.FLAG,
    RTRTRANS_INSERT_ONLY.O_EFFCT_SRT_DT,
    RTRTRANS_INSERT_ONLY.O_EFFCT_END_DT,
    RTRTRANS_INSERT_ONLY.O_ACTIVE_FLAG,
    RTRTRANS_INSERT_ONLY.EDW_LAST_UPDT_USERID1,
    RTRTRANS_INSERT_ONLY.EDW_LAST_UPDT_TS1,
    0 AS DML_FLAG
  FROM RTRTRANS_INSERT_ONLY
),

EXPTRANS2 AS (
  SELECT
    EXPTRANS1.* ,
    CURRENT_TIMESTAMP() AS UPD_EFFCT_END_DT1,
    'N' AS UPD_ACTIVE_FLAG1
  FROM EXPTRANS1
),

UPDTRANS1 AS (
  SELECT
    EXPTRANS1.BDY_PRT_ID,
    EXPTRANS1.INJRY_ILLNSS_ID,
    EXPTRANS1.CREATED_DT,
    EXPTRANS1.MODIFIED_DT,
    EXPTRANS1.RECORD_NM,
    EXPTRANS1.RECORD_NB,
    EXPTRANS1.BDY_PRT_NM,
    EXPTRANS1.INJ_NTR_TX,
    EXPTRANS1.HIGH_ENRGY_HZRD_TX,
    EXPTRANS1.INJRY_SUSTAIN_1_TX,
    EXPTRANS1.INJRY_SUSTAIN_2_TX,
    EXPTRANS1.BDY_PRT_GRP_TX,
    EXPTRANS1.SRC_CHECKSUM,
    EXPTRANS1.LKP_CHECKSUM,
    EXPTRANS1.FLAG,
    EXPTRANS1.O_EFFCT_SRT_DT,
    EXPTRANS1.O_EFFCT_END_DT,
    EXPTRANS1.O_ACTIVE_FLAG,
    EXPTRANS1.EDW_LAST_UPDT_USERID1,
    EXPTRANS1.EDW_LAST_UPDT_TS1,
    0 AS DML_FLAG
  FROM EXPTRANS1
) ,

UPDTRANS AS (
  SELECT
    EXPTRANS2.BDY_PRT_ID,
    EXPTRANS2.INJRY_ILLNSS_ID,
    EXPTRANS2.CREATED_DT,
    EXPTRANS2.MODIFIED_DT,
    EXPTRANS2.RECORD_NM,
    EXPTRANS2.RECORD_NB,
    EXPTRANS2.BDY_PRT_NM,
    EXPTRANS2.INJ_NTR_TX,
    EXPTRANS2.HIGH_ENRGY_HZRD_TX,
    EXPTRANS2.INJRY_SUSTAIN_1_TX,
    EXPTRANS2.INJRY_SUSTAIN_2_TX,
    EXPTRANS2.BDY_PRT_GRP_TX,
    EXPTRANS2.SRC_CHECKSUM,
    EXPTRANS2.LKP_CHECKSUM,
    EXPTRANS2.FLAG,
    EXPTRANS2.O_EFFCT_SRT_DT,
    EXPTRANS2.O_EFFCT_END_DT,
    EXPTRANS2.O_ACTIVE_FLAG,
    EXPTRANS2.EDW_LAST_UPDT_USERID1,
    EXPTRANS2.EDW_LAST_UPDT_TS1,
    EXPTRANS2.UPD_EFFCT_END_DT1 AS O_EFFCT_END_DT1,
    EXPTRANS2.UPD_ACTIVE_FLAG1 AS O_ACTIVE_FLAG1,
    1 AS DML_FLAG,
    EXPTRANS2.LKP_BDY_PRT_KEY as BDY_PRT_KEY
  FROM EXPTRANS2
)
SELECT  BDY_PRT_KEY, BDY_PRT_ID,INJRY_ILLNSS_ID,CREATED_DT, MODIFIED_DT, RECORD_NM, RECORD_NB, BDY_PRT_NM, INJ_NTR_TX, O_EFFCT_SRT_DT, O_EFFCT_END_DT1, O_ACTIVE_FLAG1, EDW_LAST_UPDT_USERID1, EDW_LAST_UPDT_TS1, HIGH_ENRGY_HZRD_TX, INJRY_SUSTAIN_1_TX, INJRY_SUSTAIN_2_TX, BDY_PRT_GRP_TX,DML_FLAG
FROM UPDTRANS
) src
WHERE tgt.BDY_PRT_KEY = src.BDY_PRT_KEY
  AND src.DML_FLAG = 1;
